import{_ as t,o as i,c as s,a2 as e}from"./chunks/framework.wfnuidXa.js";const k=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md","lastUpdated":1780989355000}'),d={name:"guide/quick-start.md"};function l(h,a,o,n,p,r){return i(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>本页面向第一次部署 LiteWaf 的用户，目标是在已安装 Docker Engine 和 Docker Compose v2 的 Linux 服务器上启动生产栈，并完成后台和网关验证。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><ul><li>推荐 Debian 12 minimal，也兼容主流 Linux 发行版。</li><li>Docker Engine 已安装，<code>docker compose version</code> 可正常输出。</li><li><code>80</code>、<code>443</code>、后台端口 <code>18080</code>、API loopback 端口 <code>18081</code> 以及后续要发布的应用监听端口未被占用。</li><li>当前用户可以执行 Docker 命令；非 root 用户按部署脚本提示使用 <code>sudo</code>。</li></ul><h2 id="一行部署" tabindex="-1">一行部署 <a class="header-anchor" href="#一行部署" aria-label="Permalink to &quot;一行部署&quot;">​</a></h2><p>GitHub 入口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/newz-max/litewaf-api/master/deploy/manager.sh)&quot;</span></span></code></pre></div><p>Gitee 入口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://gitee.com/old_records/litewaf-api/raw/master/deploy/manager.sh)&quot;</span></span></code></pre></div><p>安装脚本会下载生产 Compose、环境变量模板和运维脚本到 <code>/opt/litewaf</code>，生成 <code>.env</code>，拉取预构建镜像并等待服务健康。</p><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服务</th><th>地址</th><th>说明</th></tr></thead><tbody><tr><td>Dashboard</td><td><code>http://服务器IP:18080</code></td><td>后台管理页面</td></tr><tr><td>Gateway</td><td>发布应用的监听端口</td><td>OpenResty WAF 网关</td></tr><tr><td>API</td><td>Dashboard <code>/api/</code> 反代</td><td>控制面 API</td></tr><tr><td>PostgreSQL</td><td>Compose 内部网络</td><td>配置、用户和日志存储</td></tr><tr><td>Redis</td><td>Compose 内部网络</td><td>轻量运行状态</td></tr></tbody></table><p>安装后可在服务器上查看后台账号和端口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/litewaf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;^(DASHBOARD_PORT|GATEWAY_LISTENER_MODE|API_LOOPBACK_PORT|LITEWAF_ADMIN_USERNAME|LITEWAF_ADMIN_PASSWORD)=&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span></code></pre></div><h2 id="首次验证" tabindex="-1">首次验证 <a class="header-anchor" href="#首次验证" aria-label="Permalink to &quot;首次验证&quot;">​</a></h2><ol><li>登录 Dashboard。</li><li>创建站点并配置源站。</li><li>添加或启用基础防护规则。</li><li>发布当前配置。</li><li>通过 Gateway 访问应用，确认正常请求被代理。</li><li>发起一条可被规则命中的测试请求，确认 WAF 日志出现拦截记录。</li></ol><div class="warning custom-block"><p class="custom-block-title">发布要求</p><p>站点、规则、策略、IP 名单、访问控制、限流和防护模块配置变更后，必须发布配置，Gateway 才会执行新版本。</p></div><p>更多手动部署、GeoIP 和运维命令见 <a href="./../deploy/debian12">Debian 12 部署</a>。</p>`,18)])])}const u=t(d,[["render",l]]);export{k as __pageData,u as default};
